 1→# Adelie Investment - Nginx 리버스 프록시 설정 (표준 포트 80)
 2→server {
 3→    listen 80;
 4→    server_name _;
 5→
 6→    root /usr/share/nginx/html;
 7→    index index.html;
 8→
 9→    # gzip 압축
10→    gzip on;
11→    gzip_types text/plain text/css application/json application/javascript text/xml application/xml text/javascript image/svg+xml;
12→    gzip_min_length 256;
13→
14→    # Frontend SPA 라우팅
15→    location / {
16→        try_files $uri $uri/ /index.html;
17→    }
18→
19→    # FastAPI 라우팅 (/api/v1/*)
20→    location /api/v1/ {
21→        proxy_pass http://backend-api:8082;
22→        proxy_set_header Host $host;
23→        proxy_set_header X-Real-IP $remote_addr;
24→        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
25→        proxy_set_header X-Forwarded-Proto $scheme;
26→        # SSE 스트리밍 지원 (Tutor 챗봇)
27→        proxy_buffering off;
28→        proxy_cache off;
29→        proxy_read_timeout 300s;
30→    }
31→
32→    # 레거시 인증 경로 호환 (/api/auth/* → /api/v1/auth/*)
33→    location /api/auth/ {
34→        rewrite ^/api/auth/(.*)$ /api/v1/auth/$1 break;
35→        proxy_pass http://backend-api:8082;
36→        proxy_set_header Host $host;
37→        proxy_set_header X-Real-IP $remote_addr;
38→        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
39→    }
40→
41→    # 헬스체크
42→    location /api/health {
43→        proxy_pass http://backend-api:8082;
44→        proxy_set_header Host $host;
45→    }
46→
47→    # PWA Service Worker (캐시 방지)
48→    location /sw.js {
49→        add_header Cache-Control "no-cache";
50→        try_files $uri =404;
51→    }
52→
53→    # PWA Manifest (캐시 방지)
54→    location /manifest.webmanifest {
55→        add_header Cache-Control "no-cache";
56→        try_files $uri =404;
57→    }
58→
59→    # 정적 자산 장기 캐싱
60→    location ~* \.(js|css|png|jpg|jpeg|gif|ico|svg|woff2?)$ {
61→        expires 7d;
62→        add_header Cache-Control "public, immutable";
63→    }
64→}
