  1→import { useEffect, useState } from 'react';
  2→
  3→const DEFAULT_THRESHOLD_PX = 56;
  4→const MOBILE_WIDTH_PX = 1024;
  5→
  6→function isElement(value) {
  7→  return typeof HTMLElement !== 'undefined' && value instanceof HTMLElement;
  8→}
  9→
 10→function matchesTrackedTarget(target, selector) {
 11→  if (!isElement(target)) return false;
 12→  if (target.matches(selector)) return true;
 13→  return Boolean(target.closest(selector));
 14→}
 15→
 16→export default function useKeyboardInset({
 17→  trackedSelector = '[data-agent-dock-input]',
 18→  thresholdPx = DEFAULT_THRESHOLD_PX,
 19→} = {}) {
 20→  const [keyboardOffset, setKeyboardOffset] = useState(0);
 21→  const [keyboardOpen, setKeyboardOpen] = useState(false);
 22→  const [inputFocused, setInputFocused] = useState(false);
 23→  const [isMobileViewport, setIsMobileViewport] = useState(false);
 24→
 25→  useEffect(() => {
 26→    const viewport = window.visualViewport;
 27→    const mobileQuery = window.matchMedia('(max-width: 1024px)');
 28→    const coarsePointerQuery = window.matchMedia('(pointer: coarse)');
 29→
 30→    const updateViewportClass = () => {
 31→      const byWidth = mobileQuery.matches || window.innerWidth <= MOBILE_WIDTH_PX;
 32→      const byPointer = coarsePointerQuery.matches;
 33→      setIsMobileViewport(byWidth && byPointer);
 34→    };
 35→
 36→    const updateViewport = () => {
 37→      if (!viewport) {
 38→        setKeyboardOffset(0);
 39→        setKeyboardOpen(false);
 40→        return;
 41→      }
 42→
 43→      const nextOffset = Math.max(
 44→        0,
 45→        Math.round(window.innerHeight - viewport.height - viewport.offsetTop),
 46→      );
 47→
 48→      setKeyboardOffset(nextOffset);
 49→      setKeyboardOpen(nextOffset > thresholdPx);
 50→    };
 51→
 52→    updateViewportClass();
 53→    updateViewport();
 54→
 55→    if (viewport) {
 56→      viewport.addEventListener('resize', updateViewport);
 57→      viewport.addEventListener('scroll', updateViewport);
 58→    }
 59→
 60→    const addQueryListener = (query, handler) => {
 61→      if (typeof query.addEventListener === 'function') {
 62→        query.addEventListener('change', handler);
 63→        return () => query.removeEventListener('change', handler);
 64→      }
 65→      query.addListener(handler);
 66→      return () => query.removeListener(handler);
 67→    };
 68→
 69→    window.addEventListener('resize', updateViewport);
 70→    window.addEventListener('resize', updateViewportClass);
 71→    const removeMobileQueryListener = addQueryListener(mobileQuery, updateViewportClass);
 72→    const removeCoarseQueryListener = addQueryListener(coarsePointerQuery, updateViewportClass);
 73→
 74→    return () => {
 75→      if (viewport) {
 76→        viewport.removeEventListener('resize', updateViewport);
 77→        viewport.removeEventListener('scroll', updateViewport);
 78→      }
 79→      window.removeEventListener('resize', updateViewport);
 80→      window.removeEventListener('resize', updateViewportClass);
 81→      removeMobileQueryListener();
 82→      removeCoarseQueryListener();
 83→    };
 84→  }, [thresholdPx]);
 85→
 86→  useEffect(() => {
 87→    const handleFocusIn = (event) => {
 88→      if (matchesTrackedTarget(event.target, trackedSelector)) {
 89→        setInputFocused(true);
 90→      }
 91→    };
 92→
 93→    const handleFocusOut = () => {
 94→      requestAnimationFrame(() => {
 95→        const active = document.activeElement;
 96→        setInputFocused(matchesTrackedTarget(active, trackedSelector));
 97→      });
 98→    };
 99→
100→    document.addEventListener('focusin', handleFocusIn);
101→    document.addEventListener('focusout', handleFocusOut);
102→
103→    handleFocusOut();
104→
105→    return () => {
106→      document.removeEventListener('focusin', handleFocusIn);
107→      document.removeEventListener('focusout', handleFocusOut);
108→    };
109→  }, [trackedSelector]);
110→
111→  return {
112→    keyboardOffset,
113→    keyboardOpen,
114→    inputFocused,
115→    isMobileViewport,
116→    shouldHideBottomNav: isMobileViewport && (keyboardOpen || inputFocused),
117→  };
118→}
