 61→const SWIPE_THRESHOLD = 70;
 62→const slideVariants = {
 63→  enter: (direction) => ({
 64→    x: direction > 0 ? 80 : -80,
 65→    opacity: 0,
 66→  }),
 67→  center: {
 68→    x: 0,
 69→    opacity: 1,
 70→  },
 71→  exit: (direction) => ({
 72→    x: direction > 0 ? -80 : 80,
 73→    opacity: 0,
 74→  }),
 75→};
