 77→export default function Landing() {
 78→  const navigate = useNavigate();
 79→  const { user, isLoading } = useUser();
 80→  const isAuthenticated = !!user?.isAuthenticated;
 81→  const [currentIndex, setCurrentIndex] = useState(0);
 82→  const [direction, setDirection] = useState(1);
 83→  const hasAutoAdvancedRef = useRef(false);
 84→
 85→  const currentSlide = useMemo(() => LANDING_SLIDES[currentIndex], [currentIndex]);
 86→  const totalSlides = LANDING_SLIDES.length;
 87→  const featureSlides = LANDING_SLIDES.slice(1);
 88→  const showControls = currentIndex > 0;
 89→  const isLastSlide = currentIndex === totalSlides - 1;
 90→
 91→  useEffect(() => {
 92→    if (isLoading || !isAuthenticated) return undefined;
 93→    const timer = setTimeout(() => {
 94→      navigate('/home', { replace: true });
 95→    }, 1000);
 96→    return () => clearTimeout(timer);
 97→  }, [isLoading, isAuthenticated, navigate]);
 98→
 99→  useEffect(() => {
100→    LANDING_SLIDES.forEach((slide) => {
101→      const img = new Image();
102→      img.src = slide.image;
103→    });
104→  }, []);
105→
106→  useEffect(() => {
107→    if (isLoading || isAuthenticated) return undefined;
108→    if (currentIndex !== 0 || hasAutoAdvancedRef.current) return undefined;
109→
110→    const timer = setTimeout(() => {
111→      hasAutoAdvancedRef.current = true;
112→      setDirection(1);
113→      setCurrentIndex(1);
114→    }, 3000);
115→
116→    return () => clearTimeout(timer);
117→  }, [currentIndex, isAuthenticated, isLoading]);
118→
119→  useEffect(() => {
120→    if (currentIndex > 0) {
121→      hasAutoAdvancedRef.current = true;
122→    }
123→  }, [currentIndex]);
124→
125→  const goToSlide = (index, explicitDirection) => {
126→    const normalized = Math.max(0, Math.min(index, totalSlides - 1));
127→    if (normalized === currentIndex) return;
128→    const nextDirection = explicitDirection ?? (normalized > currentIndex ? 1 : -1);
129→    setDirection(nextDirection);
130→    setCurrentIndex(normalized);
131→  };
132→
133→  // feature 슬라이드(index 1 이상)에서만 이전 가능
134→  const goPrev = () => {
135→    if (currentIndex <= 1) return;
136→    goToSlide(currentIndex - 1, -1);
137→  };
138→
139→  // 마지막 슬라이드에서 순환 방지
140→  const goNext = () => {
141→    if (currentIndex >= totalSlides - 1) return;
142→    goToSlide(currentIndex + 1, 1);
143→  };
144→
145→  const skipToLast = () => {
146→    goToSlide(totalSlides - 1, 1);
147→  };
148→
149→  const handleDragEnd = (_, info) => {
