152→
153→    if (offsetX <= -SWIPE_THRESHOLD || velocityX <= -500) {
154→      goNext();
155→      return;
156→    }
157→
158→    if (offsetX >= SWIPE_THRESHOLD || velocityX >= 500) {
159→      goPrev();
160→    }
161→  };
162→
163→  return (
164→    <div className="min-h-[100dvh] bg-background">
165→      <main className="relative mx-auto flex min-h-[100dvh] w-full max-w-mobile flex-col overflow-hidden">
166→        <AnimatePresence mode="wait" custom={direction}>
167→          <motion.section
168→            key={currentSlide.id}
169→            custom={direction}
170→            variants={slideVariants}
171→            initial="enter"
172→            animate="center"
173→            exit="exit"
174→            transition={{ duration: 0.35, ease: [0.22, 1, 0.36, 1] }}
175→            drag="x"
176→            dragConstraints={{ left: 0, right: 0 }}
177→            dragElastic={0.12}
178→            onDragEnd={handleDragEnd}
179→            className="relative flex flex-1 flex-col touch-pan-y"
180→          >
181→            {!isLastSlide ? (
182→              <button
183→                type="button"
184→                onClick={skipToLast}
185→                aria-label="랜딩 건너뛰기"
186→                className="absolute right-4 top-5 z-20 rounded-full border border-white/40 bg-white/25 px-3 py-1.5 text-xs font-semibold text-black backdrop-blur-md transition hover:bg-white/35"
187→              >
188→                건너뛰기
189→              </button>
190→            ) : null}
191→
192→            {currentSlide.type === 'hero' ? (
193→              <>
194→                <div className="pt-16 text-center">
195→                  <p className="text-[clamp(3rem,20vw,5.5rem)] leading-none font-black tracking-[-0.03em] text-black">
196→                    {currentSlide.brand}
197→                  </p>
198→                  <p className="mt-5 text-[24px] leading-tight text-black">
199→                    <span className="font-bold text-primary">{currentSlide.highlightTitle} </span>
200→                    {currentSlide.subtitle}
201→                  </p>
202→                </div>
203→
204→                <img
205→                  src={currentSlide.image}
206→                  alt="ADELIE 랜딩 메인 비주얼"
207→                  className="pointer-events-none absolute [bottom:calc(-1*clamp(1.5rem,8vw,3.6rem))] left-1/2 z-0 w-[clamp(130%,calc(40vw_+_90%),170%)] max-w-none -translate-x-[58%] select-none"
208→                />
209→              </>
210→            ) : (
211→              <>
212→                <section className="px-4 pt-[clamp(2rem,12vw,5rem)]">
213→                  <h1 className="line-limit-2 text-[clamp(2rem,8.2vw,2.35rem)] leading-[1.2] font-extrabold tracking-[-0.03em] whitespace-pre-wrap text-black">
