 43→  if (!caseId) return <Navigate to="/search" replace />;
 44→  return <Navigate to={`/narrative/${caseId}`} replace />;
 45→}
 46→
 47→function ProtectedRoute({ children }) {
 48→  const { user, isLoading } = useUser();
 49→  if (isLoading) return <PageLoader />;
 50→  if (!user?.isAuthenticated) return <Navigate to="/" replace />;
 51→  return children;
 52→}
 53→
 54→function PageLoader() {
 55→  return (
 56→    <div className="min-h-screen bg-background flex items-center justify-center">
 57→      <PenguinLoading size="sm" />
 58→    </div>
 59→  );
 60→}
 61→
 62→function PageViewTracker() {
 63→  const location = useLocation();
 64→  useEffect(() => {
 65→    trackPageView(location.pathname);
 66→  }, [location.pathname]);
 67→  return null;
 68→}
 69→
 70→function AppRoutes() {
 71→  return (
 72→    <Suspense fallback={<PageLoader />}>
 73→      <Routes>
 74→        <Route path="/" element={<Landing />} />
